UPDATE cart
SET f_dstatus = -1
WHERE c_code = #{c_code}
  AND id = #{id}
  AND f_status = 'Y'
  AND f_dstatus IN (0, 1)

UPDATE cart
SET f_dstatus = #{f_dstatus}
WHERE c_code = #{c_code}
  AND id = #{id}
  AND f_status = 'Y'

